import {
  forwardRef,
  useState,
  useRef,
  useImperativeHandle,
  type ChangeEvent,
} from "react";
import {
  type InputProps as AriaInputProps,
  Input as AriaInput,
} from "react-aria-components";
import * as styles from "./Input.css";
import type { InputSize, InputType, InputValidation } from "./Input.config";
import { DEFAULT_INPUT_SIZE, DEFAULT_INPUT_TYPE } from "./Input.config";
import clsx from "clsx";
import EyeIcon from "@fortawesome/fontawesome-pro/svgs/regular/eye.svg";
import EyeSlashIcon from "@fortawesome/fontawesome-pro/svgs/regular/eye-slash.svg";
import MagnifyingGlassIcon from "@fortawesome/fontawesome-pro/svgs/regular/magnifying-glass.svg";
import XmarkIcon from "@fortawesome/fontawesome-pro/svgs/regular/xmark.svg";
import { Button } from "../Button/Button";

// Base props shared by all input types
interface BaseInputProps {
  /**
   * The size of the input
   * @default 'md'
   */
  size?: InputSize;

  /**
   * The validation state of the input
   */
  validation?: InputValidation | undefined;
}

// Props specific to password inputs
interface PasswordInputProps extends BaseInputProps {
  type: "password";

  /**
   * Accessibility label for the "show password" button
   * Required when type="password"
   */
  showPasswordLabel: string;

  /**
   * Accessibility label for the "hide password" button
   * Required when type="password"
   */
  hidePasswordLabel: string;

  clearSearchLabel?: never;
  onClear?: never;
}

// Props specific to search inputs (requires controlled usage)
interface SearchInputProps extends BaseInputProps {
  type: "search";

  /**
   * Accessibility label for the "clear search" button
   * Required when type="search"
   */
  clearSearchLabel: string;

  /**
   * Callback when the clear button is clicked
   */
  onClear?: () => void;

  /**
   * The current value of the input (required for search inputs)
   */
  value: string;

  /**
   * Change handler (required for search inputs)
   */
  onChange: (e: ChangeEvent<HTMLInputElement>) => void;

  showPasswordLabel?: never;
  hidePasswordLabel?: never;
}

// Standard input types (not password or search)
type StandardInputType = Exclude<InputType, "password" | "search">;

interface StandardInputProps extends BaseInputProps {
  /**
   * The type of the input
   * @default 'text'
   */
  type?: StandardInputType;

  showPasswordLabel?: never;
  hidePasswordLabel?: never;
  clearSearchLabel?: never;
  onClear?: never;
}

type CustomInputPropsKeys =
  | keyof BaseInputProps
  | "type"
  | "showPasswordLabel"
  | "hidePasswordLabel"
  | "clearSearchLabel"
  | "onClear"
  | "aria-invalid";

// Base props type for Aria
type BaseAriaProps = Omit<AriaInputProps, CustomInputPropsKeys>;

// Discriminated union for type-safe props
export type InputProps = BaseAriaProps &
  (PasswordInputProps | SearchInputProps | StandardInputProps);

export const Input = forwardRef<HTMLInputElement, InputProps>(
  (
    {
      size = DEFAULT_INPUT_SIZE,
      validation,
      className,
      type = DEFAULT_INPUT_TYPE,
      disabled,
      readOnly,
      showPasswordLabel,
      hidePasswordLabel,
      clearSearchLabel,
      onClear,
      value,
      defaultValue,
      ...props
    },
    ref
  ) => {
    const [showPassword, setShowPassword] = useState(false);
    const internalRef = useRef<HTMLInputElement>(null);

    // Expose the internal ref to the parent via forwardRef
    useImperativeHandle(ref, () => internalRef.current as HTMLInputElement, []);

    const isPassword = type === "password";
    const isSearch = type === "search";

    // Determine if we need the wrapper layout (password and search have built-in addons)
    const hasAddons = isPassword || isSearch;

    // For password inputs, toggle between text and password
    const resolvedType = isPassword && showPassword ? "text" : type;

    // Render password toggle button using Button component
    const passwordToggle = isPassword ? (
      <Button
        type="button"
        variant="ghost"
        color="neutral"
        size="sm"
        onClick={() => setShowPassword(!showPassword)}
        disabled={disabled}
        aria-disabled={disabled || undefined}
        aria-label={showPassword ? hidePasswordLabel : showPasswordLabel}
        aria-pressed={showPassword}
        iconOnly
        iconStart={
          showPassword ? (
            <EyeSlashIcon width={16} height={16} aria-hidden="true" />
          ) : (
            <EyeIcon width={16} height={16} aria-hidden="true" />
          )
        }
      />
    ) : null;

    // Render search icon
    const searchIcon = isSearch ? (
      <MagnifyingGlassIcon
        width={20}
        height={20}
        aria-hidden="true"
        className={styles.searchIcon}
      />
    ) : null;

    // Handle clear button click - clear value and refocus input
    const handleClear = () => {
      onClear?.();
      // Focus the input after clearing
      internalRef.current?.focus();
    };

    // Render clear button for search (only show when there's a value and not disabled/readonly)
    const hasValue = Boolean(value);
    const showClearButton = isSearch && hasValue && !disabled && !readOnly;
    const clearButton = showClearButton ? (
      <Button
        type="button"
        variant="ghost"
        color="neutral"
        size="sm"
        onClick={handleClear}
        aria-label={clearSearchLabel}
        iconOnly
        iconStart={<XmarkIcon width={16} height={16} aria-hidden="true" />}
      />
    ) : null;

    // Start addon: search icon for search inputs
    const startAddon = searchIcon;

    // End addon: password toggle for password inputs, clear button for search inputs
    const endAddon = isPassword
      ? passwordToggle
      : isSearch
        ? clearButton
        : null;

    const isInvalid = validation === "invalid";

    // If we have addons, use wrapper layout
    if (hasAddons) {
      const wrapperClasses = clsx(
        styles.inputWrapper({
          size,
          isDisabled: disabled ?? false,
          isReadOnly: readOnly ?? false,
        }),
        className
      );

      return (
        <div
          className={wrapperClasses}
          data-validation={validation ?? undefined}
        >
          {startAddon && (
            <span className={styles.addonContainer}>{startAddon}</span>
          )}
          <AriaInput
            ref={internalRef}
            className={styles.inputInner}
            type={resolvedType}
            disabled={disabled}
            readOnly={readOnly}
            aria-invalid={isInvalid || undefined}
            {...props}
            value={value}
            defaultValue={defaultValue}
          />
          {endAddon && (
            <span className={styles.addonContainer}>{endAddon}</span>
          )}
        </div>
      );
    }

    // Simple input without addons
    const inputClasses = clsx(
      styles.input({
        size,
      }),
      className
    );

    return (
      <AriaInput
        ref={internalRef}
        className={inputClasses}
        type={resolvedType}
        disabled={disabled}
        readOnly={readOnly}
        data-validation={validation ?? undefined}
        aria-invalid={isInvalid || undefined}
        {...props}
        value={value}
        defaultValue={defaultValue}
      />
    );
  }
);

Input.displayName = "Input";
