export const InputSizes = ["sm", "md"] as const;
export type InputSize = (typeof InputSizes)[number];

// Allowed input types (whitelist) - text-based only
const AllowedInputTypes = [
  "text",
  "search",
  "tel",
  "url",
  "email",
  "password",
  "number",
  "date",
  "month",
  "week",
  "time",
  "datetime-local",
] as const;
export type AllowedInputType = (typeof AllowedInputTypes)[number];

// Input type is restricted to allowed types only (type-level whitelist)
export type InputType = AllowedInputType;

// Exported for convenience
export const InputTypes = AllowedInputTypes;

// Validation states for input
export const InputValidations = ["invalid", "valid"] as const;
export type InputValidation = (typeof InputValidations)[number];

// Defaults derived from the same source
export const DEFAULT_INPUT_SIZE: InputSize = "md";
export const DEFAULT_INPUT_TYPE: InputType = "text";
